	                        case REPORT_KIND_GPIO_DEP1_EN_ON:
	                        case REPORT_KIND_GPIO_DEP1_EN_OFF:
	                        case REPORT_KIND_GPIO_DEP2_EN_ON:
	                        case REPORT_KIND_GPIO_DEP2_EN_OFF:
