            while (total--) crc ^= *(p++);
            command->romasyncrxcmd.CmdHeader[7] = crc;

            packetsign* pkt = (packetsign*)malloc(2 + 2 + 4 + sizeof(PAYUEL_ROMA_SyncRxCmd_t));
            pkt->Identifier = HVD_TEST;
