            uint8_t crc = 0xFF;

            while (total--) crc ^= *(p++);
            command->romasynctxcmd.CmdHeader[7] = crc;

            packetsign* pkt = (packetsign*)malloc(2 + 2 + 4 + sizeof(PAYUEL_ROMA_SyncTxCmd_t));
            pkt->Identifier = HVD_TEST;
